####################
 # FUNCTION iauracadnormalise #
####################
def iauracadnormalise(arg,):
	'''
	:param arg
	:type arg:iauracadvectorordirection
	'''
	if ( not EXISTS(arg)):
		return  None
	else:
		ndim = arg.dim
		if ('Iauracad2X3.IauracadVECTOR'  ==  TYPEOF(arg)):
			# begin/end block
			v.directionratios = arg.iauracadvector.orientation.directionratios
			vec.magnitude = arg.iauracadvector.magnitude
			vec.orientation = v
			if (arg.magnitude  ==  0):
				return  None
			else:
				vec.magnitude = 1
		else:
			v.directionratios = arg.directionratios
		mag = 0
		for  i in range(1,ndim,1):
			mag = mag  +  (v.directionratios[i]  *  v.directionratios[i])
		if (mag  >  0):
			mag = SQRT(mag)
			for  i in range(1,ndim,1):
				v.directionratios[i] = v.directionratios[i] / mag
			if ('Iauracad2X3.IauracadVECTOR'  ==  TYPEOF(arg)):
				vec.orientation = v
				result = vec
			else:
				result = v
		else:
			return  None
	return result

####################
 # FUNCTION iauracadsamevalue #
####################
def iauracadsamevalue(value1,value2,epsilon,):
	'''
	:param value1
	:type value1:REAL
	:param value2
	:type value2:REAL
	:param epsilon
	:type epsilon:REAL
	'''
	valideps = NVL(epsilon,defaulteps)
	return ((value1  +  valideps)  >  value2)  and  (value1  <  (value2  +  valideps))

