 # FUNCTION iauracadsamevalidprecision #
####################
def iauracadsamevalidprecision(epsilon1,epsilon2,):
	'''
	:param epsilon1
	:type epsilon1:REAL
	:param epsilon2
	:type epsilon2:REAL
	'''
	valideps1 = NVL(epsilon1,defaulteps)
	valideps2 = NVL(epsilon2,defaulteps)
	return (((0  <  valideps1)  and  (valideps1  <=  (derivationofeps  *  valideps2)))  and  (valideps2  <=  (derivationofeps  *  valideps1)))  and  (valideps2  <  uppereps)

####################
 # FUNCTION iauracadbuildaxes #
####################
def iauracadbuildaxes(axis,refdirection,):
	'''
	:param axis
	:type axis:iauracaddirection
	:param refdirection
	:type refdirection:iauracaddirection
	'''
	d1 = NVL(iauracadnormalise(axis),(iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([0,0,1]))
	d2 = iauracadfirstprojaxis(d1,refdirection)
	return [d2,iauracadnormalise(iauracadcrossproduct(d1,d2)).iauracadvector.orientation,d1]

####################
 # FUNCTION iauracadvectorsum #
####################
def iauracadvectorsum(arg1,arg2,):
	'''
	:param arg1
	:type arg1:iauracadvectorordirection
	:param arg2
	:type arg2:iauracadvectorordirection
	'''
	if ((( not EXISTS(arg1))  or  ( not EXISTS(arg2)))  or  (arg1.dim  !=  arg2.dim)):
		return  None
	else:
		# begin/end block
		if ('Iauracad2X3.IauracadVECTOR'  ==  TYPEOF(arg1)):
			mag1 = arg1.iauracadvector.magnitude
			vec1 = arg1.iauracadvector.orientation
		else:
			mag1 = 1
			vec1 = arg1
		if ('Iauracad2X3.IauracadVECTOR'  ==  TYPEOF(arg2)):
			mag2 = arg2.iauracadvector.magnitude
			vec2 = arg2.iauracadvector.orientation
		else:
			mag2 = 1
			vec2 = arg2
		vec1 = iauracadnormalise(vec1)
		vec2 = iauracadnormalise(vec2)
		ndim = SIZEOF(vec1.directionratios)
		mag = 0
		res = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([0,ndim])
		for  i in range(1,ndim,1):
			res.directionratios[i] = (mag1  *  vec1.directionratios[i])  +  (mag2  *  vec2.directionratios[i])
			mag = mag  +  (res.directionratios[i]  *  res.directionratios[i])
		if (mag  >  0):
			result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(res,SQRT(mag))
		else:
			result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(vec1,0)
	return result

####################
 # FUNCTION iauracadvectordifference #
####################
def iauracadvectordifference(arg1,arg2,):
	'''
	:param arg1
	:type arg1:iauracadvectorordirection
	:param arg2
	:type arg2:iauracadvectorordirection
	'''
	if ((( not EXISTS(arg1))  or  ( not EXISTS(arg2)))  or  (arg1.dim  !=  arg2.dim)):
		return  None
	else:
		# begin/end block
		if ('Iauracad2X3.IauracadVECTOR'  ==  TYPEOF(arg1)):
			mag1 = arg1.iauracadvector.magnitude
			vec1 = arg1.iauracadvector.orientation
		else:
			mag1 = 1
			vec1 = arg1
		if ('Iauracad2X3.IauracadVECTOR'  ==  TYPEOF(arg2)):
			mag2 = arg2.iauracadvector.magnitude
			vec2 = arg2.iauracadvector.orientation
		else:
			mag2 = 1
			vec2 = arg2
		vec1 = iauracadnormalise(vec1)
		vec2 = iauracadnormalise(vec2)
		ndim = SIZEOF(vec1.directionratios)
		mag = 0
		res = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([0,ndim])
		for  i in range(1,ndim,1):
			res.directionratios[i] = (mag1  *  vec1.directionratios[i]) - (mag2  *  vec2.directionratios[i])
			mag = mag  +  (res.directionratios[i]  *  res.directionratios[i])
		if (mag  >  0):
			result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(res,SQRT(mag))
		else:
			result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(vec1,0)
	return result

####################
 # FUNCTION iauracadcorrectlocalplacement #
####################
def iauracadcorrectlocalplacement(axisplacement,relplacement,):
	'''
	:param axisplacement
	:type axisplacement:iauracadaxis2placement
	:param relplacement
	:type relplacement:iauracadobjectplacement
	'''
	if (EXISTS(relplacement)):
		if ('Iauracad2X3.IauracadGRIDPLACEMENT'  ==  TYPEOF(relplacement)):
			return  None
		if ('Iauracad2X3.IauracadLOCALPLACEMENT'  ==  TYPEOF(relplacement)):
			if ('Iauracad2X3.IauracadAXIS2PLACEMENT2D'  ==  TYPEOF(axisplacement)):
				return TRUE
			if ('Iauracad2X3.IauracadAXIS2PLACEMENT3D'  ==  TYPEOF(axisplacement)):
				if (relplacement.relativeplacement.dim  ==  3):
					return TRUE
				else:
					return FALSE
	else:
		return TRUE
	return  None

####################
 # FUNCTION iauracadcorrectfillareastyle #
####################
def iauracadcorrectfillareastyle(styles,):
	'''
	:param styles
	:type styles:(null)
	'''
	external = SIZEOF(None)
	hatching = SIZEOF(None)
	tiles = SIZEOF(None)
	colour = SIZEOF(None)
	if (external  >  1):
		return FALSE
	if ((external  ==  1)  and  (((hatching  >  0)  or  (tiles  >  0))  or  (colour  >  0))):
		return FALSE
	if (colour  >  1):
		return FALSE
	if ((hatching  >  0)  and  (tiles  >  0)):
		return FALSE
	return TRUE

