####################
 # FUNCTION iauracadcurvedim #
####################
def iauracadcurvedim(curve,):
	'''
	:param curve
	:type curve:iauracadcurve
	'''
	if ('Iauracad2X3.IauracadLINE'  ==  TYPEOF(curve)):
		return curve.iauracadline.pnt.dim
	if ('Iauracad2X3.IauracadCONIC'  ==  TYPEOF(curve)):
		return curve.iauracadconic.position.dim
	if ('Iauracad2X3.IauracadPOLYLINE'  ==  TYPEOF(curve)):
		return curve.iauracadpolyline.points[1].dim
	if ('Iauracad2X3.IauracadTRIMMEDCURVE'  ==  TYPEOF(curve)):
		return iauracadcurvedim(curve.iauracadtrimmedcurve.basiscurve)
	if ('Iauracad2X3.IauracadCOMPOSITECURVE'  ==  TYPEOF(curve)):
		return curve.iauracadcompositecurve.segments[1].dim
	if ('Iauracad2X3.IauracadBSPLINECURVE'  ==  TYPEOF(curve)):
		return curve.iauracadbsplinecurve.controlpointslist[1].dim
	if ('Iauracad2X3.IauracadOFFSETCURVE2D'  ==  TYPEOF(curve)):
		return 2
	if ('Iauracad2X3.IauracadOFFSETCURVE3D'  ==  TYPEOF(curve)):
		return 3
	return  None

####################
 # FUNCTION iauracadsamedirection #
####################
def iauracadsamedirection(dir1,dir2,epsilon,):
	'''
	:param dir1
	:type dir1:iauracaddirection
	:param dir2
	:type dir2:iauracaddirection
	:param epsilon
	:type epsilon:REAL
	'''
	if (SIZEOF(dir1.directionratios)  >  2):
		dir1z = dir1.directionratios[3]
	if (SIZEOF(dir2.directionratios)  >  2):
		dir2z = dir2.directionratios[3]
	return (iauracadsamevalue(dir1x,dir2x,epsilon)  and  iauracadsamevalue(dir1y,dir2y,epsilon))  and  iauracadsamevalue(dir1z,dir2z,epsilon)

####################
 # FUNCTION iauracadlisttoarray #
####################
def iauracadlisttoarray(lis,low,u,):
	'''
	:param lis
	:type lis:(null)
	:param low
	:type low:INTEGER
	:param u
	:type u:INTEGER
	'''
	n = SIZEOF(lis)
	if (n  !=  ((u - low)  +  1)):
		return  None
	else:
		res = [lis[1],n]
		for  i in range(2,n,1):
			res[(low  +  i) - 1] = lis[i]
		return res

