####################
 # FUNCTION iauracaddimensionsforsiunit #
####################
def iauracaddimensionsforsiunit(n,):
	'''
	:param n
	:type n:iauracadsiunitname
	'''
	case_selector = n
	if  case_selector == metre:
		return iauracaddimensionalexponents(1,0,0,0,0,0,0)
	elif case_selector == square_metre:
		return iauracaddimensionalexponents(2,0,0,0,0,0,0)
	elif case_selector == cubic_metre:
		return iauracaddimensionalexponents(3,0,0,0,0,0,0)
	elif case_selector == gram:
		return iauracaddimensionalexponents(0,1,0,0,0,0,0)
	elif case_selector == second:
		return iauracaddimensionalexponents(0,0,1,0,0,0,0)
	elif case_selector == ampere:
		return iauracaddimensionalexponents(0,0,0,1,0,0,0)
	elif case_selector == kelvin:
		return iauracaddimensionalexponents(0,0,0,0,1,0,0)
	elif case_selector == mole:
		return iauracaddimensionalexponents(0,0,0,0,0,1,0)
	elif case_selector == candela:
		return iauracaddimensionalexponents(0,0,0,0,0,0,1)
	elif case_selector == radian:
		return iauracaddimensionalexponents(0,0,0,0,0,0,0)
	elif case_selector == steradian:
		return iauracaddimensionalexponents(0,0,0,0,0,0,0)
	elif case_selector == hertz:
		return iauracaddimensionalexponents(0,0,-1,0,0,0,0)
	elif case_selector == newton:
		return iauracaddimensionalexponents(1,1,-2,0,0,0,0)
	elif case_selector == pascal:
		return iauracaddimensionalexponents(-1,1,-2,0,0,0,0)
	elif case_selector == joule:
		return iauracaddimensionalexponents(2,1,-2,0,0,0,0)
	elif case_selector == watt:
		return iauracaddimensionalexponents(2,1,-3,0,0,0,0)
	elif case_selector == coulomb:
		return iauracaddimensionalexponents(0,0,1,1,0,0,0)
	elif case_selector == volt:
		return iauracaddimensionalexponents(2,1,-3,-1,0,0,0)
	elif case_selector == farad:
		return iauracaddimensionalexponents(-2,-1,4,1,0,0,0)
	elif case_selector == ohm:
		return iauracaddimensionalexponents(2,1,-3,-2,0,0,0)
	elif case_selector == siemens:
		return iauracaddimensionalexponents(-2,-1,3,2,0,0,0)
	elif case_selector == weber:
		return iauracaddimensionalexponents(2,1,-2,-1,0,0,0)
	elif case_selector == tesla:
		return iauracaddimensionalexponents(0,1,-2,-1,0,0,0)
	elif case_selector == henry:
		return iauracaddimensionalexponents(2,1,-2,-2,0,0,0)
	elif case_selector == degree_celsius:
		return iauracaddimensionalexponents(0,0,0,0,1,0,0)
	elif case_selector == lumen:
		return iauracaddimensionalexponents(0,0,0,0,0,0,1)
	elif case_selector == lux:
		return iauracaddimensionalexponents(-2,0,0,0,0,0,1)
	elif case_selector == becquerel:
		return iauracaddimensionalexponents(0,0,-1,0,0,0,0)
	elif case_selector == gray:
		return iauracaddimensionalexponents(2,0,-2,0,0,0,0)
	elif case_selector == sievert:
		return iauracaddimensionalexponents(2,0,-2,0,0,0,0)
	else:
		return iauracaddimensionalexponents(0,0,0,0,0,0,0)

