 # FUNCTION iauracadmlstotalthickness #
####################
def iauracadmlstotalthickness(layerset,):
	'''
	:param layerset
	:type layerset:iauracadmateriallayerset
	'''
	if (SIZEOF(layerset.materiallayers)  >  1):
		for  i in range(2,HIINDEX(layerset.materiallayers),1):
			max = max  +  layerset.materiallayers[i].layerthickness
	return max

####################
 # FUNCTION iauracadcorrectobjectassignment #
####################
def iauracadcorrectobjectassignment(constraint,objects,):
	'''
	:param constraint
	:type constraint:iauracadobjecttypeenum
	:param objects
	:type objects:(null)
	'''
	if ( not EXISTS(constraint)):
		return TRUE
	case_selector = constraint
	if  case_selector == iauracadobjecttypeenum.notdefined:
		return TRUE
	elif case_selector == iauracadobjecttypeenum.product:
		# begin/end block
		count = SIZEOF(None)
		return count  ==  0
	elif case_selector == iauracadobjecttypeenum.process:
		# begin/end block
		count = SIZEOF(None)
		return count  ==  0
	elif case_selector == iauracadobjecttypeenum.control:
		# begin/end block
		count = SIZEOF(None)
		return count  ==  0
	elif case_selector == iauracadobjecttypeenum.resource:
		# begin/end block
		count = SIZEOF(None)
		return count  ==  0
	elif case_selector == iauracadobjecttypeenum.actor:
		# begin/end block
		count = SIZEOF(None)
		return count  ==  0
	elif case_selector == iauracadobjecttypeenum.group:
		# begin/end block
		count = SIZEOF(None)
		return count  ==  0
	elif case_selector == iauracadobjecttypeenum.project:
		# begin/end block
		count = SIZEOF(None)
		return count  ==  0
	else:
		return  None

####################
 # FUNCTION iauracadvalidcalendardate #
####################
def iauracadvalidcalendardate(date,):
	'''
	:param date
	:type date:iauracadcalendardate
	'''
	if ( not ((1  <=  date.daycomponent)  and  (date.daycomponent  <=  31))):
		return FALSE
	case_selector = date.monthcomponent
	if  case_selector == 4:
		return (1  <=  date.daycomponent)  and  (date.daycomponent  <=  30)
	elif case_selector == 6:
		return (1  <=  date.daycomponent)  and  (date.daycomponent  <=  30)
	elif case_selector == 9:
		return (1  <=  date.daycomponent)  and  (date.daycomponent  <=  30)
	elif case_selector == 11:
		return (1  <=  date.daycomponent)  and  (date.daycomponent  <=  30)
	elif case_selector == 2:
		# begin/end block
		if (iauracadleapyear(date.yearcomponent)):
			return (1  <=  date.daycomponent)  and  (date.daycomponent  <=  29)
		else:
			return (1  <=  date.daycomponent)  and  (date.daycomponent  <=  28)
	else:
		return TRUE

