 # FUNCTION iauracadcurveweightspositive #
####################
def iauracadcurveweightspositive(b,):
	'''
	:param b
	:type b:iauracadrationalbeziercurve
	'''
	for  i in range(0,b.upperindexoncontrolpoints,1):
		if (b.weights[i]  <=  0):
			result = FALSE
			return result
	return result

####################
 # FUNCTION iauracadsameaxis2placement #
####################
def iauracadsameaxis2placement(ap1,ap2,epsilon,):
	'''
	:param ap1
	:type ap1:iauracadaxis2placement
	:param ap2
	:type ap2:iauracadaxis2placement
	:param epsilon
	:type epsilon:REAL
	'''
	return (iauracadsamedirection(ap1.p[1],ap2.p[1],epsilon)  and  iauracadsamedirection(ap1.p[2],ap2.p[2],epsilon))  and  iauracadsamecartesianpoint(ap1.location,ap1.location,epsilon)

