def iauracadbuild2axes(refdirection,):
	'''
	:param refdirection
	:type refdirection:iauracaddirection
	'''
	return [d,iauracadorthogonalcomplement(d)]

####################
 # FUNCTION iauracadcrossproduct #
####################
def iauracadcrossproduct(arg1,arg2,):
	'''
	:param arg1
	:type arg1:iauracaddirection
	:param arg2
	:type arg2:iauracaddirection
	'''
	if ((( not EXISTS(arg1))  or  (arg1.dim  ==  2))  or  (( not EXISTS(arg2))  or  (arg2.dim  ==  2))):
		return  None
	else:
		# begin/end block
		v1 = iauracadnormalise(arg1).directionratios
		v2 = iauracadnormalise(arg2).directionratios
		res = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracaddirection([(v1[2]  *  v2[3]) - (v1[3]  *  v2[2]),(v1[3]  *  v2[1]) - (v1[1]  *  v2[3]),(v1[1]  *  v2[2]) - (v1[2]  *  v2[1])])
		mag = 0
		for  i in range(1,3,1):
			mag = mag  +  (res.directionratios[i]  *  res.directionratios[i])
		if (mag  >  0):
			result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(res,SQRT(mag))
		else:
			result = (iauracadrepresentationitem()  ==  iauracadgeometricrepresentationitem())  ==  iauracadvector(arg1,0)
		return result

####################
 # FUNCTION iauracadsamecartesianpoint #
####################
def iauracadsamecartesianpoint(cp1,cp2,epsilon,):
	'''
	:param cp1
	:type cp1:iauracadcartesianpoint
	:param cp2
	:type cp2:iauracadcartesianpoint
	:param epsilon
	:type epsilon:REAL
	'''
	if (SIZEOF(cp1.coordinates)  >  2):
		cp1z = cp1.coordinates[3]
	if (SIZEOF(cp2.coordinates)  >  2):
		cp2z = cp2.coordinates[3]
	return (iauracadsamevalue(cp1x,cp2x,epsilon)  and  iauracadsamevalue(cp1y,cp2y,epsilon))  and  iauracadsamevalue(cp1z,cp2z,epsilon)

